function renderizarTreinadoresComoLinks(modalidade,plano){const treinadores=dadosPlanos[modalidade][plano].treinadores;let html='<div class="treinadores-lista">';treinadores.forEach(treinador=>{const nomeArquivo=treinador.nome.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/\s+/g,"-");html+=`<a href="../pages/treinadores/${nomeArquivo}.html" target="_blank" class="treinador-badge">${treinador.nome}</a>`});html+="</div>";return html}